<template>
  <div class="container-fluid bg-light h-100" >
      <div class="row h-100">
        <div class="col-12 col-md-2  ">
          <div class="list-group mt-3  border-0 "  >
              <a @click="goToCategory"   class="list-group-item list-group-item-action text-dark fs-5 text-start" >
                全部商品
              </a>
            
              <a @click="goToCategory"  class="list-group-item list-group-item-action text-dark fs-5 text-start">
                春天系列
              </a>
              <a @click="goToCategory"  class="list-group-item list-group-item-action text-dark fs-5 text-start" >
                夏天系列
              </a>
              
              <a @click="goToCategory"  class="list-group-item list-group-item-action text-dark fs-5 text-start">
                秋天系列
              </a>
              <a @click="goToCategory"   class="list-group-item list-group-item-action text-dark fs-5 text-start">
                冬天系列
              </a>
              
          </div>
        </div>
        <div class="col-12 col-md-10 bg-light ">
          <router-view></router-view>
        </div>
      </div>
  </div>
</template>

<script>
export default {
  name:'ProductVue',
  methods:{
    goToCategory(event){
      if(event.target.innerText==='全部商品'){
        this.$router.push(`/products/category/all`)
      }
      if(event.target.innerText==='春天系列'){
        this.$router.push(`/products/category/spring`)
      }
      if(event.target.innerText==='夏天系列'){
        this.$router.push(`/products/category/summer`)
      }
      if(event.target.innerText==='秋天系列'){
        this.$router.push(`/products/category/autum`)
      }
      if(event.target.innerText==='冬天系列'){
        this.$router.push(`/products/category/winter`)
      }

    
  }
  }
  
}
</script>

<style scoped>

.list-group-item  {
  border:0px;
}

a {
  text-decoration-line: none; 
}

</style>