import { createRouter,createWebHashHistory } from 'vue-router'
import HomeVue from '../components/HomeVue'
import RegistVue from '../components/RegistVue'
import LoginVue from '../components/LoginVue'
import ForgotPassword from '../components/ForgotPassword'
import ProductsVue from '../components/Products/ProductsVue'
import ProductsShow from '../components/Products/Category/ProductsShow'
const  routes=[
        {
            path:'/',
            component:HomeVue,
            meta: {
                title: '隨心花藝'
              },
        },
        {
            path:'/registpage',
            component:RegistVue,
            meta: {
                title: '會員註冊'
              },
        },
        {
            path:'/login',
            component:LoginVue,
            meta: {
                title: '會員登入'
              },
        },
        {
            path:'/forgotpassword',
            component:ForgotPassword,
            meta: {
                title: '忘記密碼'
              },
        },
        {
            path:'/products',
            component:ProductsVue,
            meta: {
                title: '商品列表'
              },
            children:[
                {
                    path:'category/:cid',
                    component:ProductsShow,
                    
                }

            ]
        },
        {
            path:'/memberpage',
            component:()=> import('../components/MemberPage/MemberPage.vue'),
            meta: {
                title: '會員中心'
              },
            children:[
                {
                    path:'info',
                    component:()=>import('../components/MemberPage/MemberHome.vue'),
                   
                },
                {
                    path:'orders',
                    component:()=>import('../components/MemberPage/HistoryOrders.vue')
                }
            ]
        },
        {
            path:'/productdetail',
            component:()=>import('../components/Products/ProductDetail'),
            meta: {
                title: '商品詳細'
              },
        },
        {
            path:'/orderconfirm',
            component:()=>import('../components/OrderConfirm'),
            meta: {
                title: '確認訂單'
              },
        },
        {
            path:'/checkout',
            name:'checkout',
            component:()=>import('../components/CheckOut'),
            meta: {
                title: '結帳'
              },
        },
        {
            path:'/historyorderdetail',
            component:()=>import('../components/HistoryOrderDetail'),
            meta: {
                title: '歷史訂單'
              },
        },
        {
            path:'/backendlogin',
            component:()=>import('../components/BackEnd/BackEndLogin'),
            meta: {
                title: '管理員登入'
              },
        },
        {
            path:'/backenddashboard',
            component:()=>import('../components/BackEnd/BackEndDashboard'),
            meta: {
                title: '後台管理'
              },
            children:[
                {
                    path:'home',
                    component:()=>import('../components/BackEnd/BackEndHome')
                },
                {
                    path:'orders',
                    component:()=>import('../components/BackEnd/BackEndOrders'),
                },
                {
                    path:'products',
                    component:()=>import('../components/BackEnd/BackEndProducts'),
                },
                {
                    path:'customers',
                    component:()=>import('../components/BackEnd/BackEndCustomers')
                },
                {
                    path:'addproduct',
                    component:()=>import('../components/BackEnd/BackEndAddProduct')
                },
                {
                    path:'editproduct',
                    component:()=>import('../components/BackEnd/BackEndEditProduct')
                
                },
                {
                    path:'editcustomer',
                    component:()=>import('../components/BackEnd/BackEndEditCustomer')
                },
               
            ]
        }
    ]

const router= createRouter({
    history:createWebHashHistory(),
    routes,
})

router.beforeEach((to,from,next)=>{
    if(to.path == '/backenddashboard'||
       to.path == '/backenddashboard/home' ||
       to.path == '/backenddashboard/orders'||
       to.path == '/backenddashboard/customers'||
       to.path == '/backenddashboard/products'){
        const isAdminLogin= localStorage.getItem('isAdminLogin')
        if(isAdminLogin == null ||isAdminLogin =='loginFailure'|| isAdminLogin=='undefined'){
            console.log('haha')
            next('/backendlogin')
            return
        }
    }
    
    next()
})
router.afterEach((to)=>{
    const DEFAULT_TITLE = '標題';
    
        document.title=to.meta.title || DEFAULT_TITLE
})
export default router;