<script>
import {ref,reactive,computed,watch} from 'vue'
import {useCartItemsStore} from '../store/cartItems'

export default {
  name:'HeaderVue',
  
  setup(){
    let navRWDBtn=ref(false)
    let itemsNavRWDBtn=ref(false)
    let isLogin=ref(window.localStorage.getItem('isLogin'))
    let cartItemsStore=useCartItemsStore()
    let cartItems=reactive(JSON.parse(localStorage.getItem('cart')===null ? JSON.stringify({items:[]}) : localStorage.getItem('cart')))
    let isEmpty=computed(()=>{
      if(cartItems.items.length===0){
        return true
      }
      return false
    })
    let cartItemsCount=ref(cartItems.items.length)
    function checkRWD(){
      if(navRWDBtn.value===true){
        let btn =document.getElementById('RWDBtn')
        btn.click()
        navRWDBtn.value=false
      }
      if(itemsNavRWDBtn.value===true){
        let itemBtn =document.getElementById('menubtn')
        itemBtn.click()
        itemsNavRWDBtn.value=false
      }
      
    }
    function RWDTrigger(){
      navRWDBtn.value=true
    }
    function itemsNavRWDTrigger(){
      itemsNavRWDBtn.value=true
    }

    function itemsNavCheckRWD(){
      if(itemsNavRWDBtn.value ===true){
        let btn=document.getElementById('menubtn')
        btn.click()
        itemsNavRWDBtn.value=false
      }
    }
  
    watch(()=>cartItemsStore.cartItems,()=>{
      let cartItems= JSON.parse(localStorage.getItem('cart'))
      cartItemsCount.value= cartItems.items.length
    })
  
    return{
      isLogin,
      cartItems,
      isEmpty,
      cartItemsStore,
      cartItemsCount,
      checkRWD,
      RWDTrigger,
      itemsNavRWDTrigger,
      itemsNavCheckRWD
    }
  },
  methods:{
    logout(){
      window.localStorage.removeItem('isLogin')
      this.$router.push('/').then(()=>{
        window.location.reload()
      })
    },
    goCart(){
      var cartBtn= document.getElementById('goCart')
      if(localStorage.getItem('isLogin')===null){
        this.$router.push('/login')
        cartBtn.click()
        return
      }
      cartBtn.click()
      this.$router.push('/orderconfirm')
    },
    recountCart(){
      const newCartItems =JSON.parse(localStorage.getItem('cart'))
      this.cartItems.items=newCartItems.items
    },
    deleteItem(id){
      let cart=  JSON.parse(localStorage.getItem('cart'))
      for(var i=0;i<cart.items.length;i++){
        if(cart.items[i].id===id){
          cart.items.splice(i,1)
        }
      }
      localStorage.setItem('cart',JSON.stringify(cart))
      this.cartItems.items=cart.items
      this.cartItemsStore.cartTrigger()
    }
    
  },
  mounted() {
    if(localStorage.getItem('cart')===null){
      localStorage.setItem('cart',JSON.stringify({items:[]}))
    }
  },
}





</script>

